// Calculate last week's date range (Mon–Sun)
const now = new Date();
const dayOfWeek = now.getDay() || 7;
const lastMonday = new Date(now);
lastMonday.setDate(now.getDate() - dayOfWeek - 6);
lastMonday.setHours(0, 0, 0, 0);
const lastSunday = new Date(lastMonday);
lastSunday.setDate(lastMonday.getDate() + 6);
lastSunday.setHours(23, 59, 59, 999);

return [{
  json: {
    startMs: lastMonday.getTime(),
    endMs: lastSunday.getTime(),
    startDate: lastMonday.toISOString().split('T')[0],
    endDate: lastSunday.toISOString().split('T')[0]
  }
}];

// Aggregate campaign metrics
const emails = $input.first().json.results || [];
if (emails.length === 0) {
  return [{ json: { hasData: false, summary: 'No campaigns found for this period.', campaigns: [] } }];
}

const campaigns = emails.map(e => {
  const stats = e.stats || e.counters || {};
  const sent = stats.sent || stats.delivered || 0;
  const opens = stats.open || stats.opens || 0;
  const clicks = stats.click || stats.clicks || 0;
  const unsubs = stats.unsubscribed || stats.unsubscribes || 0;
  const openRate = sent > 0 ? ((opens / sent) * 100).toFixed(1) : '0';
  const clickRate = sent > 0 ? ((clicks / sent) * 100).toFixed(1) : '0';
  return {
    name: e.name || e.subject || 'Untitled',
    subject: e.subject || '',
    sent,
    opens,
    clicks,
    unsubs,
    openRate: parseFloat(openRate),
    clickRate: parseFloat(clickRate)
  };
});

const totals = {
  totalCampaigns: campaigns.length,
  totalSent: campaigns.reduce((s, c) => s + c.sent, 0),
  totalOpens: campaigns.reduce((s, c) => s + c.opens, 0),
  totalClicks: campaigns.reduce((s, c) => s + c.clicks, 0),
  totalUnsubs: campaigns.reduce((s, c) => s + c.unsubs, 0)
};
totals.avgOpenRate = totals.totalSent > 0
  ? ((totals.totalOpens / totals.totalSent) * 100).toFixed(1)
  : '0';
totals.avgClickRate = totals.totalSent > 0
  ? ((totals.totalClicks / totals.totalSent) * 100).toFixed(1)
  : '0';

const bestByOpen = [...campaigns].sort((a, b) => b.openRate - a.openRate)[0];
const bestByClick = [...campaigns].sort((a, b) => b.clickRate - a.clickRate)[0];

const campaignLines = campaigns
  .map(c => `- ${c.name}: ${c.sent} sent | ${c.openRate}% open | ${c.clickRate}% click | ${c.unsubs} unsubs`)
  .join('\n');

return [{
  json: {
    hasData: true,
    ...totals,
    bestOpenCampaign: bestByOpen ? `${bestByOpen.name} (${bestByOpen.openRate}% open rate)` : 'N/A',
    bestClickCampaign: bestByClick ? `${bestByClick.name} (${bestByClick.clickRate}% CTR)` : 'N/A',
    campaignLines,
    campaigns,
    startDate: $('Calculate Date Range').item.json.startDate,
    endDate: $('Calculate Date Range').item.json.endDate
  }
}];

